import java.sql.*;

public class SecureSQLInjectionExample {
    public static void main(String[] args) {
        try {
            // Simulating user input as a malicious SQL injection
            String userInput = "'; DROP TABLE users; --";

            // Connecting to a database (this is just for demonstration purposes)
